import { COMPONENT_TYPES } from '@/const';
import type {
  AiJson,
  AiJsonComponentType,
  AiJsonMcpEntry,
  AiJsonOriginEntry,
  AiJsonSkillEntry,
  InstallResult,
} from '@/types';
import { ResourceType, Source } from '@/types';
import { installComponent, installPlugin } from '../installEntry';

export type InstallAllParams = {
  aiJson: AiJson;
  installDir: string;
  token?: string;
  /** Called after each entry finishes */
  onProgress?: (result: InstallResult) => void;
};

export type InstallAllResult = {
  results: InstallResult[];
  successCount: number;
  failCount: number;
};

const installAll = async ({
  aiJson,
  installDir,
  token,
  onProgress,
}: InstallAllParams): Promise<InstallAllResult> => {
  const results: InstallResult[] = [];

  for (const type of COMPONENT_TYPES) {
    if (type === ResourceType.Plugin) continue;
    const section = aiJson[type as AiJsonComponentType] ?? {};

    for (const [name, entry] of Object.entries(section)) {
      if ('source' in entry && entry.source === Source.Origin) {
        const oe = entry as AiJsonOriginEntry;
        if (!oe.path?.trim()) continue;
      }
      const result = await installComponent({
        name,
        type: type as AiJsonComponentType,
        entry: entry as AiJsonSkillEntry | AiJsonMcpEntry,
        installDir,
        token,
      });
      results.push(result);
      onProgress?.(result);
    }
  }

  for (const [name, entry] of Object.entries(aiJson.plugin ?? {})) {
    if ('source' in entry && entry.source === Source.Origin) {
      const oe = entry as AiJsonOriginEntry;
      if (!oe.path?.trim()) continue;
    }
    const result = await installPlugin({ name, entry, installDir, token });
    results.push(result);
    onProgress?.(result);
  }

  return {
    results,
    successCount: results.filter((r) => r.success).length,
    failCount: results.filter((r) => !r.success).length,
  };
};

export type InstallAll = typeof installAll;

export default installAll;

