import { AI_JSON_VERSION, TRACKED_SOURCES } from '@/const';
import { getEnv } from '@/core/config';

/**
 * Resolve the $schema URL for ai-package.json, based on the current web_url config.
 */
export const getAiJsonSchemaUrl = (): string => {
  const webUrl = (getEnv({ key: 'webUrl' }) || 'https://ai-skills.bytedance.net').replace(
    /\/+$/,
    ''
  );
  return `${webUrl}/aijson/${AI_JSON_VERSION}/schema.json`;
};

export type BuildAiJsonSchemaParams = {
  /** Schema version, defaults to AI_JSON_VERSION */
  version?: string;
  /** Base URL for $id, defaults to https://ai-skills.bytedance.net */
  baseUrl?: string;
};

const buildAiJsonSchema = (params?: BuildAiJsonSchemaParams): Record<string, unknown> => {
  const version = params?.version ?? AI_JSON_VERSION;
  const baseUrl = (params?.baseUrl ?? 'https://ai-skills.bytedance.net').replace(/\/+$/, '');

  const trackedSourceEnum = [...TRACKED_SOURCES];

  /* ── Reusable $defs ───────────────────────────────── */

  const gitTrackedEntry = {
    type: 'object',
    description:
      'Git-tracked entry from github/codebase/local/team/workspace sources. ' +
      'Version is pinned via "sha@<hex>" (github/codebase) or semver (local/team/workspace). ' +
      'gitPath disambiguates same-name items within the same repo.',
    required: ['source', 'owner', 'repo', 'version', 'gitPath'],
    properties: {
      source: {
        type: 'string',
        enum: trackedSourceEnum,
        description: 'Tracked distribution source type.',
      },
      owner: { type: 'string', description: 'Repository owner or organization.' },
      repo: { type: 'string', description: 'Repository name (or collection name).' },
      version: {
        type: 'string',
        description: 'Version identifier — "sha@<hex>" for github/codebase, semver for local/team.',
        examples: ['sha@abcd1234ef567890abcd1234ef567890abcd1234', '1.0.0'],
      },
      gitPath: {
        type: 'string',
        description:
          'Path relative to the repository root. Empty string: resolve at install via SKILL.md discovery using the manifest skill key.',
      },
      branch: {
        type: 'string',
        description: 'Branch or tag; omitted when installed from the default branch.',
      },
    },
    additionalProperties: false,
  };

  const originEntry = {
    type: 'object',
    description:
      'Project-original content — not version-tracked. Optional path: project-relative or absolute; used to reinstall from disk.',
    required: ['source'],
    properties: {
      source: { type: 'string', const: 'origin' },
      path: {
        type: 'string',
        description:
          'Directory or .zip containing the skill/plugin; project-relative to ai-package.json parent, or absolute (e.g. global installs).',
      },
    },
    additionalProperties: false,
  };

  /* ── Discriminated union definitions ────────────── */

  const pluginEntry = {
    description: 'Plugin entry — git-tracked or project-original.',
    oneOf: [{ $ref: '#/$defs/gitTrackedEntry' }, { $ref: '#/$defs/originEntry' }],
  };

  const skillEntry = {
    description: 'Skill entry — git-tracked or project-original.',
    oneOf: [{ $ref: '#/$defs/gitTrackedEntry' }, { $ref: '#/$defs/originEntry' }],
  };

  const mcpEntry = {
    description: 'MCP entry — git-tracked or project-original.',
    oneOf: [{ $ref: '#/$defs/gitTrackedEntry' }, { $ref: '#/$defs/originEntry' }],
  };

  /* ── Root schema ──────────────────────────────────── */

  return {
    $schema: 'http://json-schema.org/draft-07/schema#',
    $id: `${baseUrl}/aijson/${version}/schema.json`,
    title: 'ai-package.json',
    description:
      'AI Skills CLI project manifest — tracks installed skills, MCPs, and plugins with source provenance.',
    type: 'object',
    properties: {
      $schema: {
        type: 'string',
        description: 'Optional JSON Schema URL for editor validation (CLI does not write this).',
      },
      name: {
        type: 'string',
        description: 'Project name.',
      },
      registry: {
        type: 'string',
        description:
          'Optional; defaults to CLI web_url / SKILL_HUB. Omitted from disk — resolved at read time.',
      },
      plugin: {
        type: 'object',
        description: 'Installed plugins (keyed by plugin name).',
        additionalProperties: { $ref: '#/$defs/pluginEntry' },
      },
      skill: {
        type: 'object',
        description: 'Installed standalone skills (keyed by skill name).',
        additionalProperties: { $ref: '#/$defs/skillEntry' },
      },
      mcp: {
        type: 'object',
        description: 'Installed standalone MCPs (keyed by MCP name).',
        additionalProperties: { $ref: '#/$defs/mcpEntry' },
      },
    },
    additionalProperties: false,
    $defs: {
      gitTrackedEntry,
      originEntry,
      pluginEntry,
      skillEntry,
      mcpEntry,
    },
  };
};

export type BuildAiJsonSchema = typeof buildAiJsonSchema;

export default buildAiJsonSchema;

import { join } from 'node:path';
import { INSTALL_SUBDIRS } from '@/const';
import { getEnv } from '@/core/config';
import { linkOrCopy, writeFiles } from '@/core/fileOps';
import {
  extractPluginFilesForName,
  extractSkillFilesForName,
  loadAiJsonFilesFromOriginAbsPath,
  originKeyFromAbsPath,
  recordOriginResolvedAbs,
  resolveOriginSourcePath,
} from '@/core/origin';
import type {
  AiJsonComponentType,
  AiJsonGitTrackedEntry,
  AiJsonMcpEntry,
  AiJsonOriginEntry,
  AiJsonPluginEntry,
  AiJsonSkillEntry,
  InstallResult,
  ResourceType,
} from '@/types';
import { Source } from '@/types';
import resolveSource from '../resolveSource';

export type InstallComponentParams = {
  name: string;
  type: AiJsonComponentType;
  entry: AiJsonSkillEntry | AiJsonMcpEntry;
  installDir: string;
  token?: string;
};

export type InstallPluginParams = {
  name: string;
  entry: AiJsonPluginEntry;
  installDir: string;
  token?: string;
};

/**
 * Build the cache directory path:
 * {cache}/{source}/{owner}/{repo}/{version}/{type}/{name}
 */
const buildCachePath = (
  source: string,
  owner: string,
  repo: string,
  version: string,
  type: string,
  name: string
): string => {
  const cacheRoot = getEnv({ key: 'cache' });
  const safeVersion = version.replace(/[/:*?"<>|]/g, '_');
  return join(cacheRoot, source, owner, repo, safeVersion, type, name);
};

/**
 * Install a component: write files to cache, create symlink in installDir.
 */
const installComponent = async ({
  name,
  type,
  entry,
  installDir,
  token,
}: InstallComponentParams): Promise<InstallResult> => {
  if (entry.source === Source.Origin) {
    const oe = entry as AiJsonOriginEntry;
    const pathRes = resolveOriginSourcePath(oe.path, installDir);
    if (!pathRes.ok) {
      return { name, type, success: false, error: pathRes.error };
    }
    const loaded = await loadAiJsonFilesFromOriginAbsPath(pathRes.abs);
    if (!loaded.ok) {
      return { name, type, success: false, error: loaded.error };
    }
    if (type === 'mcp') {
      return {
        name,
        type,
        success: false,
        error: 'origin_mcp_flat_install_unsupported',
      };
    }
    const extracted = extractSkillFilesForName(name, loaded.files);
    if ('error' in extracted) {
      return { name, type, success: false, error: extracted.error };
    }
    const originKey = originKeyFromAbsPath(pathRes.abs);
    const cacheRoot = getEnv({ key: 'cache' });
    const cachePath = join(cacheRoot, 'origin', 'path', originKey, name);
    recordOriginResolvedAbs(originKey, pathRes.abs);
    const writeResult = writeFiles({ targetDir: cachePath, files: extracted.files });
    if (!writeResult.success) {
      return { name, type, success: false, error: writeResult.error };
    }
    const subdir = INSTALL_SUBDIRS[type] ?? type;
    const linkPath = join(installDir, subdir, name);
    const installResult = linkOrCopy({ target: cachePath, link: linkPath });
    if (!installResult.success) {
      return { name, type, success: false, error: installResult.error };
    }
    return { name, type, success: true, path: linkPath };
  }

  const tracked = entry as AiJsonGitTrackedEntry;
  const resolved = await resolveSource(
    {
      source: tracked.source,
      owner: tracked.owner,
      repo: tracked.repo,
      version: tracked.version,
      gitPath: tracked.gitPath,
      token,
      resourceName: name,
    },
    type as ResourceType
  );

  if (!resolved.success || !resolved.files) {
    return { name, type, success: false, error: resolved.error };
  }

  const cachePath = buildCachePath(
    tracked.source,
    tracked.owner,
    tracked.repo,
    tracked.version,
    type,
    name
  );

  const writeResult = writeFiles({ targetDir: cachePath, files: resolved.files });
  if (!writeResult.success) {
    return { name, type, success: false, error: writeResult.error };
  }

  const subdir = INSTALL_SUBDIRS[type] ?? type;
  const linkPath = join(installDir, subdir, name);
  const installResult = linkOrCopy({ target: cachePath, link: linkPath });
  if (!installResult.success) {
    return { name, type, success: false, error: installResult.error };
  }

  return { name, type, success: true, path: linkPath };
};

/**
 * Install a plugin: write files to cache, link or copy into installDir.
 */
const installPlugin = async ({
  name,
  entry,
  installDir,
  token,
}: InstallPluginParams): Promise<InstallResult> => {
  if (entry.source === Source.Origin) {
    const oe = entry as AiJsonOriginEntry;
    const pathRes = resolveOriginSourcePath(oe.path, installDir);
    if (!pathRes.ok) {
      return { name, type: 'plugin', success: false, error: pathRes.error };
    }
    const loaded = await loadAiJsonFilesFromOriginAbsPath(pathRes.abs);
    if (!loaded.ok) {
      return { name, type: 'plugin', success: false, error: loaded.error };
    }
    const extracted = extractPluginFilesForName(name, loaded.files);
    if ('error' in extracted) {
      return { name, type: 'plugin', success: false, error: extracted.error };
    }
    const originKey = originKeyFromAbsPath(pathRes.abs);
    const cacheRoot = getEnv({ key: 'cache' });
    const cachePath = join(cacheRoot, 'origin', 'path', originKey, 'plugin', name);
    recordOriginResolvedAbs(originKey, pathRes.abs);
    const writeResult = writeFiles({ targetDir: cachePath, files: extracted.files });
    if (!writeResult.success) {
      return { name, type: 'plugin', success: false, error: writeResult.error };
    }
    const subdir = INSTALL_SUBDIRS.plugin ?? 'plugin';
    const linkPath = join(installDir, subdir, name);
    const installResult = linkOrCopy({ target: cachePath, link: linkPath });
    if (!installResult.success) {
      return { name, type: 'plugin', success: false, error: installResult.error };
    }
    return { name, type: 'plugin', success: true, path: linkPath };
  }

  const tracked = entry as AiJsonGitTrackedEntry;
  const resolved = await resolveSource({
    source: tracked.source,
    owner: tracked.owner,
    repo: tracked.repo,
    version: tracked.version,
    gitPath: tracked.gitPath,
    token,
  });

  if (!resolved.success || !resolved.files) {
    return { name, type: 'plugin', success: false, error: resolved.error };
  }

  const cachePath = buildCachePath(
    tracked.source,
    tracked.owner,
    tracked.repo,
    tracked.version,
    'plugin',
    name
  );

  const writeResult = writeFiles({ targetDir: cachePath, files: resolved.files });
  if (!writeResult.success) {
    return { name, type: 'plugin', success: false, error: writeResult.error };
