import type { AiJsonSource } from '@/types';

// ── Types ────────────────────────────────────────────

export type ParseSkillSourceParams = {
  source: string;
  platform?: string;
  gitPath?: string;
};

export type ParseSkillSourceResult = {
  success: boolean;
  owner?: string;
  repo?: string;
  gitPath?: string;
  /** Branch or tag extracted from the URL (e.g. "v0.4.0" from /tree/v0.4.0/path) */
  branch?: string;
  platform?: AiJsonSource;
  name?: string;
  error?: string;
  /** True when the input is an HTTP(S) URL that does not match any known git host */
  isDirectUrl?: boolean;
  /** The raw URL when isDirectUrl is true */
  url?: string;
  /** Credentials extracted from URL userinfo ("username:token" or "token"); never persisted to ai-package.json */
  urlCredentials?: string;
};

export type ParseSkillSource = (params: ParseSkillSourceParams) => ParseSkillSourceResult;

// ── Git host registry ────────────────────────────────

type GitHostEntry = {
  host: string;
  pathPrefix: string;
  platform: 'github' | 'codebase';
};

const GIT_HOSTS: GitHostEntry[] = [
  { host: 'github.com', pathPrefix: '', platform: 'github' },
  { host: 'code.byted.org', pathPrefix: '', platform: 'codebase' },
  { host: 'bits.bytedance.net', pathPrefix: '/code', platform: 'codebase' },
];

const TREE_KEYWORDS = new Set(['tree', 'blob', '-']);

function matchGitHost(hostname: string): GitHostEntry | null {
  const exact = GIT_HOSTS.find((h) => h.host === hostname);
  if (exact) return exact;
  if (hostname.includes('codebase')) {
    return { host: hostname, pathPrefix: '', platform: 'codebase' };
  }
  return null;
}

function parseGitUrl(urlStr: string): {
  platform: 'github' | 'codebase';
  owner: string;
  repo: string;
  gitPath?: string;
  branch?: string;
  urlCredentials?: string;
} | null {
  let url: URL;
  try {
    url = new URL(urlStr);
  } catch {
    return null;
  }

  const entry = matchGitHost(url.hostname);
  if (!entry) return null;

  let urlCredentials: string | undefined;
  if (url.password) {
    urlCredentials = `${decodeURIComponent(url.username)}:${decodeURIComponent(url.password)}`;
  } else if (url.username) {
    urlCredentials = decodeURIComponent(url.username);
  }

  let pathname = url.pathname;
  if (pathname.endsWith('.git')) pathname = pathname.slice(0, -4);
  if (entry.pathPrefix && pathname.startsWith(entry.pathPrefix)) {
    pathname = pathname.slice(entry.pathPrefix.length);
  }

  const segments = pathname.split('/').filter(Boolean);
  if (segments.length < 2) return null;

  const owner = segments[0];
  const repo = segments[1];

  let gitPath: string | undefined;
  let branch: string | undefined;

  if (segments.length >= 4 && TREE_KEYWORDS.has(segments[2])) {
    if (
      segments[2] === '-' &&
      segments.length >= 5 &&
      (segments[3] === 'tree' || segments[3] === 'blob')
    ) {
      branch = segments[4];
      const sub = segments.slice(5);
      if (sub.length > 0) gitPath = sub.join('/');
    } else {
      branch = segments[3];
      const sub = segments.slice(4);
      if (sub.length > 0) gitPath = sub.join('/');
    }
  }

  return { platform: entry.platform, owner, repo, gitPath, branch, urlCredentials };
}

// ── Helpers ──────────────────────────────────────────

/**
 * GitHub/Git URLs often point at .../SKILL.md. Treat the skill root as the parent
 * directory so install uses the folder name (e.g. lark-doc) and fetches the whole skill.
 */
const normalizeRepoSkillGitPath = (gitPath: string): string => {
  const n = (gitPath || '.').replace(/\/+$/, '') || '.';
  if (n === '.') return '.';
  const lastSlash = n.lastIndexOf('/');
  const base = lastSlash === -1 ? n : n.slice(lastSlash + 1);
  if (base.toLowerCase() === 'skill.md') {
    if (lastSlash === -1) return '.';
    const parent = n.slice(0, lastSlash);
    return parent || '.';
  }
  return n;
};

const extractNameFromPath = (gitPath: string): string | undefined => {
  if (!gitPath || gitPath === '.') return undefined;
  const segments = gitPath.replace(/\/+$/, '').split('/').filter(Boolean);
  return segments[segments.length - 1] || undefined;
};

// ── Main ─────────────────────────────────────────────

const parseSkillSource: ParseSkillSource = (params) => {
  const { source, platform: platformOverride, gitPath: gitPathOverride } = params;
  const trimmed = source.trim();

  if (!trimmed) {
    return { success: false, error: 'Source is required' };
  }

  // ── SSH URL: git@host:owner/repo.git ───────────────
  if (trimmed.startsWith('git@')) {
    const m = trimmed.match(/^git@([^:]+):(.+?)(?:\.git)?$/);
    if (!m) {
      return { success: false, error: `Invalid SSH URL: ${trimmed}` };
    }
    const host = m[1];
    const pathStr = m[2];
    const entry = matchGitHost(host);
    const platform = entry?.platform ?? 'github';

    let pathname = pathStr;
    if (entry?.pathPrefix && pathname.startsWith(entry.pathPrefix.slice(1))) {
      pathname = pathname.slice(entry.pathPrefix.length - 1);
    }

    const segments = pathname.split('/').filter(Boolean);
    if (segments.length < 2) {
      return { success: false, error: `Cannot extract owner/repo from SSH URL: ${trimmed}` };
    }

    const owner = segments[0];
    const repo = segments[1];
    const pathParts = segments.slice(2);
    const raw = gitPathOverride ?? (pathParts.length > 0 ? pathParts.join('/') : '.');
    const gitPath = normalizeRepoSkillGitPath(raw);
    return {
      success: true,
      owner,
      repo,
      gitPath,
      platform: (platformOverride as AiJsonSource) ?? platform,
      name: extractNameFromPath(gitPath),
    };
  }

  // ── HTTP(S) URL ────────────────────────────────────
  if (trimmed.startsWith('http://') || trimmed.startsWith('https://')) {
    const parsed = parseGitUrl(trimmed);
    if (parsed) {
      const raw = gitPathOverride ?? (parsed.gitPath?.replace(/\/+$/, '') || '.');
      const gitPath = normalizeRepoSkillGitPath(raw);
      return {
        success: true,
        owner: parsed.owner,
        repo: parsed.repo,
        gitPath,
        branch: parsed.branch,
        platform: (platformOverride as AiJsonSource) ?? parsed.platform,
        name: extractNameFromPath(gitPath),
        urlCredentials: parsed.urlCredentials,
      };
    }
    return { success: true, isDirectUrl: true, url: trimmed };
  }

  const parts = trimmed.split('/');

  if (parts.length >= 2) {
    const owner = parts[0];
    const repo = parts[1];
    const pathParts = parts.slice(2);
    const raw = gitPathOverride ?? (pathParts.length > 0 ? pathParts.join('/') : '.');
    const gitPath = normalizeRepoSkillGitPath(raw);
    return {
      success: true,
      owner,
      repo,
      gitPath,
      platform: (platformOverride as AiJsonSource) ?? 'github',
      name: extractNameFromPath(gitPath),
    };
  }

  return {
    success: true,
    name: trimmed,
    platform: (platformOverride as AiJsonSource) ?? 'local',
  };
};

export default parseSkillSource;

