  const segments = gitPath.replace(/\/+$/, '').split('/').filter(Boolean);
  return segments[segments.length - 1] || undefined;
};

// ── Main ─────────────────────────────────────────────

const parseSkillSource: ParseSkillSource = (params) => {
  const { source, platform: platformOverride, gitPath: gitPathOverride } = params;
  const trimmed = source.trim();

  if (!trimmed) {
    return { success: false, error: 'Source is required' };
  }

  // ── SSH URL: git@host:owner/repo.git ───────────────
  if (trimmed.startsWith('git@')) {
    const m = trimmed.match(/^git@([^:]+):(.+?)(?:\.git)?$/);
    if (!m) {
      return { success: false, error: `Invalid SSH URL: ${trimmed}` };
    }
    const host = m[1];
    const pathStr = m[2];
    const entry = matchGitHost(host);
    const platform = entry?.platform ?? 'github';

    let pathname = pathStr;
    if (entry?.pathPrefix && pathname.startsWith(entry.pathPrefix.slice(1))) {
      pathname = pathname.slice(entry.pathPrefix.length - 1);
    }

    const segments = pathname.split('/').filter(Boolean);
    if (segments.length < 2) {
      return { success: false, error: `Cannot extract owner/repo from SSH URL: ${trimmed}` };
    }

    const owner = segments[0];
    const repo = segments[1];
    const pathParts = segments.slice(2);
    const raw = gitPathOverride ?? (pathParts.length > 0 ? pathParts.join('/') : '.');
    const gitPath = normalizeRepoSkillGitPath(raw);
    return {
      success: true,
      owner,
      repo,
      gitPath,
      platform: (platformOverride as AiJsonSource) ?? platform,
      name: extractNameFromPath(gitPath),
    };
  }

  // ── HTTP(S) URL ────────────────────────────────────
  if (trimmed.startsWith('http://') || trimmed.startsWith('https://')) {
    const parsed = parseGitUrl(trimmed);
    if (parsed) {
      const raw = gitPathOverride ?? (parsed.gitPath?.replace(/\/+$/, '') || '.');
      const gitPath = normalizeRepoSkillGitPath(raw);
      return {
        success: true,
        owner: parsed.owner,
        repo: parsed.repo,
        gitPath,
        branch: parsed.branch,
        platform: (platformOverride as AiJsonSource) ?? parsed.platform,
        name: extractNameFromPath(gitPath),
        urlCredentials: parsed.urlCredentials,
      };
    }
    return { success: true, isDirectUrl: true, url: trimmed };
  }

  const parts = trimmed.split('/');

  if (parts.length >= 2) {
    const owner = parts[0];
    const repo = parts[1];
    const pathParts = parts.slice(2);
    const raw = gitPathOverride ?? (pathParts.length > 0 ? pathParts.join('/') : '.');
    const gitPath = normalizeRepoSkillGitPath(raw);
    return {
      success: true,
      owner,
      repo,
      gitPath,
      platform: (platformOverride as AiJsonSource) ?? 'github',
      name: extractNameFromPath(gitPath),
    };
  }

  return {
    success: true,
    name: trimmed,
    platform: (platformOverride as AiJsonSource) ?? 'local',
  };
};

export default parseSkillSource;

