import { spawn } from 'node:child_process';
import { mkdtemp, rm } from 'node:fs/promises';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import type { CloneRequest, ClonedSource } from './types.ts';

export class GitCommandError extends Error {
  constructor(
    message: string,
    readonly args: string[],
    readonly stderr: string
  ) {
    super(message);
    this.name = 'GitCommandError';
  }
}

export const cloneRemoteSource = async (
  request: CloneRequest
): Promise<ClonedSource> => {
  const tempDir = await mkdtemp(join(tmpdir(), 'ai-pkgs-'));

  try {
    await runGit(['clone', '--no-checkout', request.cloneUrl, tempDir]);
    await runGit(['checkout', '--detach', request.commitSha], tempDir);
  } catch (error) {
    await rm(tempDir, { force: true, recursive: true });
    if (error instanceof Error) {
      throw error;
    }
    throw new Error(String(error));
  }

  return {
    rootDir: tempDir,
    cleanup: async () => {
      await rm(tempDir, { force: true, recursive: true });
    },
  };
};

const runGit = async (args: string[], cwd?: string) => {
  const stderr: string[] = [];

  await new Promise<void>((resolve, reject) => {
    const child = spawn('git', args, {
      cwd,
      env: {
        ...process.env,
        GIT_TERMINAL_PROMPT: '0',
        GIT_LFS_SKIP_SMUDGE: '1',
      },
      stdio: ['ignore', 'ignore', 'pipe'],
    });

    child.stderr.setEncoding('utf-8');
    child.stderr.on('data', (chunk: string) => {
      stderr.push(chunk);
    });

    child.on('error', reject);
    child.on('close', (code) => {
      if (code === 0) {
        resolve();
        return;
      }

      const output = stderr.join('').trim();
      reject(
        new GitCommandError(
          `git ${args.join(' ')} failed${output ? `: ${output}` : ''}`,
          args,
          output
        )
      );
    });
  });
};

import { cp, mkdir, rm, stat } from 'node:fs/promises';
import { dirname, join, relative, resolve, sep } from 'node:path';
import { cloneRemoteSource } from './git.ts';
import type {
  AiPackageManifest,
  CloneRequest,
  CloneSource,
  ClonedSource,
  InstallProgress,
  InstalledSkill,
  RemoteSkillEntry,
  SkillEntry,
} from './types.ts';

type InstallSkillsOptions = {
  manifest: AiPackageManifest;
  projectDir: string;
  targetDir?: string;
  cloneSource?: CloneSource;
  onProgress?: (progress: InstallProgress) => void;
};

type NormalizedClonedSource = {
  rootDir: string;
  cleanup?: () => Promise<void>;
};

type InstallSkillsResult = {
  installed: InstalledSkill[];
};

export const installSkills = async ({
  manifest,
  projectDir,
  targetDir = join(projectDir, '.agents/skills'),
  cloneSource = cloneRemoteSource,
  onProgress,
}: InstallSkillsOptions): Promise<InstallSkillsResult> => {
  const installed: InstalledSkill[] = [];
  const clonedSources = new Map<string, Promise<NormalizedClonedSource>>();

  try {
    for (const skill of manifest.skills) {
      const sourceRoot = await resolveSourceRoot(skill, cloneSource, clonedSources);
      onProgress?.({ name: skill.name, status: 'copying' });

      const sourceSkillDir = resolveInsideSource(sourceRoot, skill.path);
      await assertSkillDirectory(sourceSkillDir, skill.name);

      const skillTargetDir = join(targetDir, skill.name);
      await replaceDirectory(sourceSkillDir, skillTargetDir);

      installed.push({ name: skill.name, targetDir: skillTargetDir });
      onProgress?.({ name: skill.name, status: 'installed' });
    }
  } finally {
    const clones = await Promise.allSettled(clonedSources.values());
    await Promise.all(
      clones.map(async (clone) => {
        if (clone.status === 'fulfilled') {
          await clone.value.cleanup?.();
        }
      })
    );
  }

  return { installed };
};

const resolveSourceRoot = async (
  skill: SkillEntry,
  cloneSource: CloneSource,
  clonedSources: Map<string, Promise<NormalizedClonedSource>>
): Promise<string> => {
  if (skill.provider === 'file') {
    return skill.sourceRoot;
  }

  const key = remoteSourceKey(skill);
  let source = clonedSources.get(key);
  if (!source) {
    const request = remoteCloneRequest(skill);
    source = cloneSource(request).then(normalizeClonedSource);
    clonedSources.set(key, source);
  }

  return (await source).rootDir;
};

const remoteCloneRequest = (skill: RemoteSkillEntry): CloneRequest => ({
  provider: skill.provider,
  packageId: skill.packageId,
  cloneUrl: skill.cloneUrl,
  ref: skill.ref,
  commitSha: skill.commitSha,
});

const remoteSourceKey = (skill: RemoteSkillEntry): string =>
  `${skill.provider}:${skill.packageId}@${skill.commitSha}`;

const normalizeClonedSource = (source: ClonedSource): NormalizedClonedSource => {
  if (typeof source === 'string') {
    return { rootDir: source };
  }

  return source;
};

const resolveInsideSource = (sourceRoot: string, manifestPath: string): string => {
  const root = resolve(sourceRoot);
  const resolved = resolve(root, manifestPath);
  const rel = relative(root, resolved);
  if (rel.startsWith('..') || rel === '..' || rel.includes(`..${sep}`)) {
    throw new Error(`Skill path "${manifestPath}" must stay inside the source`);
  }

  return resolved;
};

const assertSkillDirectory = async (skillDir: string, name: string) => {
  let dirStats;
  try {
    dirStats = await stat(skillDir);
  } catch {
    throw new Error(`Skill "${name}" path does not exist: ${skillDir}`);
  }

  if (!dirStats.isDirectory()) {
    throw new Error(`Skill "${name}" path must be a directory: ${skillDir}`);
  }

  try {
    const skillFile = await stat(join(skillDir, 'SKILL.md'));
    if (!skillFile.isFile()) {
      throw new Error();
    }
  } catch {
    throw new Error(`Skill "${name}" path does not contain SKILL.md`);
  }
};

const replaceDirectory = async (sourceDir: string, targetDir: string) => {
  await rm(targetDir, { force: true, recursive: true });
  await mkdir(dirname(targetDir), { recursive: true });
  await cp(sourceDir, targetDir, {
    recursive: true,
    verbatimSymlinks: false,
  });
};

import { dirname, isAbsolute, resolve } from 'node:path';
import type {
  AiPackageManifest,
  FileSkillEntry,
  RemoteProvider,
  RemoteSkillEntry,
  SkillEntry,
} from './types.ts';

type RawManifest = {
  skills?: unknown;
  skill?: unknown;
};

type RawSkillEntry = {
  source?: unknown;
  version?: unknown;
  path?: unknown;
};

const REMOTE_PROVIDERS = new Set<RemoteProvider>(['github', 'gitlab']);
const COMMIT_SHA_RE = /^[0-9a-f]{7,40}$/i;

export const parseAiPackageManifest = (
  raw: unknown,
  manifestPath: string
): AiPackageManifest => {
  if (!isRecord(raw)) {
    throw new Error(`${manifestPath} must be a JSON object`);
  }

  const manifest = raw as RawManifest;
  if (manifest.skills === undefined) {
    if (manifest.skill !== undefined) {
      throw new Error(
        `${manifestPath} must use the top-level "skills" object, not "skill"`
      );
    }
    throw new Error(`${manifestPath} must contain a top-level "skills" object`);
  }

  if (!isRecord(manifest.skills)) {
    throw new Error(`${manifestPath} top-level "skills" must be an object`);
  }

  const manifestDir = dirname(resolve(manifestPath));
  const skills: SkillEntry[] = [];
  for (const [name, value] of Object.entries(manifest.skills)) {
    skills.push(parseSkillEntry(name, value, manifestDir));
  }

  return { skills };
};

const parseSkillEntry = (
  name: string,
  raw: unknown,
  manifestDir: string
): SkillEntry => {
  validateSkillName(name);

  if (!isRecord(raw)) {
    throw new Error(`Skill "${name}" must be an object`);
  }

  const entry = raw as RawSkillEntry;
  if (typeof entry.source !== 'string' || entry.source.trim().length === 0) {
    throw new Error(`Skill "${name}" source is required`);
  }

  if (typeof entry.path !== 'string' || entry.path.trim().length === 0) {
    throw new Error(`Skill "${name}" path is required`);
  }

  const path = sanitizeManifestPath(entry.path, `Skill "${name}" path`);
  const source = parseSource(entry.source, name);

  if (source.provider === 'file') {
    return {
      name,
      provider: 'file',
      packageId: source.packageId,
      sourceRoot: resolveFileSource(manifestDir, source.packageId),
      path,
    } satisfies FileSkillEntry;
  }

  if (source.provider === 'marketplace') {
    throw new Error('marketplace sources are not supported by this installer yet');
  }

  const version = parseRemoteVersion(entry.version, name);
  return {
    name,
    provider: source.provider,
    packageId: source.packageId,
    cloneUrl: buildCloneUrl(source.provider, source.packageId),
    ref: version.ref,
    commitSha: version.commitSha,
    path,
  } satisfies RemoteSkillEntry;
};

const parseSource = (
  source: string,
  skillName: string
):
  | { provider: RemoteProvider; packageId: string }
  | { provider: 'file'; packageId: string }
  | { provider: 'marketplace'; packageId: string } => {
  const separator = source.indexOf(':');
  if (separator <= 0) {
    throw new Error(
      `Skill "${skillName}" source must use <provider>:<package-id>`
    );
  }

  const provider = source.slice(0, separator);
  const packageId = source.slice(separator + 1).replace(/^\/+|\/+$/g, '');
  if (packageId.length === 0) {
    throw new Error(`Skill "${skillName}" source package id is required`);
  }

  if (REMOTE_PROVIDERS.has(provider as RemoteProvider)) {
    validateRemotePackageId(provider as RemoteProvider, packageId, skillName);
    return { provider: provider as RemoteProvider, packageId };
  }

  if (provider === 'file') {
    return { provider, packageId: source.slice(separator + 1) };
  }

  if (provider === 'marketplace') {
    return { provider, packageId };
  }

  throw new Error(`Unsupported source provider "${provider}"`);
};

const parseRemoteVersion = (
  version: unknown,
  skillName: string
): { ref: string; commitSha: string } => {
  if (typeof version !== 'string' || version.trim().length === 0) {
    throw new Error(`Skill "${skillName}" version is required for remote sources`);
  }

  const separator = version.lastIndexOf('@');
  if (separator <= 0 || separator === version.length - 1) {
    throw new Error(
      `Skill "${skillName}" version must use <ref>@<commitSha>`
    );
  }

  const ref = version.slice(0, separator);
  const commitSha = version.slice(separator + 1);
  if (!COMMIT_SHA_RE.test(commitSha)) {
    throw new Error(
      `Skill "${skillName}" version must use <ref>@<commitSha>`
    );
  }

  return { ref, commitSha };
};

export const sanitizeManifestPath = (path: string, label = 'path'): string => {
  const normalized = path.trim().replace(/\\/g, '/').replace(/^\.\/+/, '');
  if (normalized.length === 0) {
    throw new Error(`${label} is required`);
  }

  if (isAbsolute(normalized)) {
    throw new Error(`${label} must stay inside the source`);
  }

  const segments = normalized.split('/');
  if (segments.some((segment) => segment === '..')) {
    throw new Error(`${label} must stay inside the source`);
  }

  return normalized;
};

const validateSkillName = (name: string) => {
  if (
    name.trim().length === 0 ||
    name === '.' ||
    name === '..' ||
    name.includes('/') ||
    name.includes('\\')
  ) {
    throw new Error(`Invalid skill name "${name}"`);
  }
};

const validateRemotePackageId = (
  provider: RemoteProvider,
  packageId: string,
  skillName: string
) => {
  const segments = packageId.split('/').filter(Boolean);
  if (provider === 'github' && segments.length !== 2) {
    throw new Error(
      `Skill "${skillName}" github source must use github:owner/repo`
    );
  }

  if (provider === 'gitlab' && segments.length < 2) {
    throw new Error(
      `Skill "${skillName}" gitlab source must use gitlab:group/repo`
    );
  }
};

const buildCloneUrl = (provider: RemoteProvider, packageId: string): string => {
  if (provider === 'github') {
    return `https://github.com/${packageId}.git`;
  }

  return `https://gitlab.com/${packageId}.git`;
};

const resolveFileSource = (manifestDir: string, packageId: string): string => {
  if (isAbsolute(packageId)) {
    return resolve(packageId);
  }

  return resolve(manifestDir, packageId);
};

const isRecord = (value: unknown): value is Record<string, unknown> =>
  typeof value === 'object' && value !== null && !Array.isArray(value);

export type RemoteProvider = 'github' | 'gitlab';

export type SkillProvider = RemoteProvider | 'file';

export type RemoteSkillEntry = {
  name: string;
  provider: RemoteProvider;
  packageId: string;
  cloneUrl: string;
  ref: string;
  commitSha: string;
  path: string;
};

export type FileSkillEntry = {
  name: string;
  provider: 'file';
  packageId: string;
  sourceRoot: string;
  path: string;
};

export type SkillEntry = RemoteSkillEntry | FileSkillEntry;

export type AiPackageManifest = {
  skills: SkillEntry[];
};

export type CloneRequest = {
  provider: RemoteProvider;
  packageId: string;
  cloneUrl: string;
  ref: string;
  commitSha: string;
};

export type ClonedSource =
  | string
  | {
      rootDir: string;
      cleanup?: () => Promise<void>;
    };

export type CloneSource = (request: CloneRequest) => Promise<ClonedSource>;

export type InstalledSkill = {
  name: string;
  targetDir: string;
};

export type InstallProgress = {
  name: string;
  status: 'cloning' | 'copying' | 'installed';
};

