    expect(parseCliArgs(['--help'])).toMatchObject({
      command: 'help',
      help: true,
    });
  });

  it('rejects unknown commands', () => {
    expect(() => parseCliArgs(['publish'])).toThrow(CliUsageError);
  });
});

