import { describe, expect, it } from 'vitest';
import { CliUsageError, parseCliArgs } from './cli.ts';

describe('parseCliArgs', () => {
  it('defaults to install with ai-package.json in the current directory', () => {
    expect(parseCliArgs([])).toEqual({
      command: 'install',
      manifestPath: 'ai-package.json',
      projectDir: process.cwd(),
      yes: false,
      help: false,
    });
  });

  it('parses install options', () => {
    expect(
      parseCliArgs([
        'install',
        '--manifest',
        'config/ai-package.json',
        '--dir',
        '/tmp/project',
        '--yes',
      ])
    ).toEqual({
      command: 'install',
      manifestPath: 'config/ai-package.json',
      projectDir: '/tmp/project',
      yes: true,
      help: false,
    });
  });

  it('supports help flags', () => {
    expect(parseCliArgs(['--help'])).toMatchObject({
      command: 'help',
      help: true,
    });
  });

  it('rejects unknown commands', () => {
    expect(() => parseCliArgs(['publish'])).toThrow(CliUsageError);
  });
});

