  command: string,
  args: string[],
  cwd: string,
  env: Record<string, string> = {}
): Promise<{ code: number; output: string }> =>
  new Promise((resolve, reject) => {
    const process = Bun.spawn([command, ...args], {
      cwd,
      env: { ...Bun.env, ...env },
      stderr: 'pipe',
      stdout: 'pipe',
    });

    Promise.all([
      new Response(process.stdout).text(),
      new Response(process.stderr).text(),
      process.exited,
    ])
