import { spawn } from 'node:child_process';
import { mkdir, readFile, writeFile } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import { fileURLToPath, pathToFileURL } from 'node:url';
import { afterEach, beforeEach, describe, expect, it } from 'vitest';

let tempRoot: string;

beforeEach(async () => {
  tempRoot = await mkdtemp();
});

afterEach(async () => {
  await rmTemp(tempRoot);
});

describe('ai-pkgs install e2e', () => {
  it('installs pinned github and gitlab skills through the CLI', async () => {
    const githubRepo = join(tempRoot, 'github-repo');
    const gitlabRepo = join(tempRoot, 'gitlab-repo');
    const projectDir = join(tempRoot, 'project');
    await mkdir(projectDir, { recursive: true });

    const githubCommit = await createGitRepo(
      githubRepo,
      'skills/github-skill',
      '# GitHub Skill'
    );
    const gitlabCommit = await createGitRepo(
      gitlabRepo,
      'nested/gitlab-skill',
      '# GitLab Skill'
    );

    const gitConfigPath = join(tempRoot, 'gitconfig');
    await writeFile(
      gitConfigPath,
      [
        `[url "${pathToFileURL(githubRepo).href}"]`,
        '\tinsteadOf = https://github.com/acme/skills.git',
        `[url "${pathToFileURL(gitlabRepo).href}"]`,
        '\tinsteadOf = https://gitlab.com/team/platform/skills.git',
        '',
      ].join('\n')
    );

    await writeFile(
      join(projectDir, 'ai-package.json'),
      JSON.stringify(
        {
          skills: {
            'github-installed': {
              source: 'github:acme/skills',
              version: `main@${githubCommit}`,
              path: 'skills/github-skill',
            },
            'gitlab-installed': {
              source: 'gitlab:team/platform/skills',
              version: `main@${gitlabCommit}`,
              path: 'nested/gitlab-skill',
            },
          },
        },
        null,
        2
      )
    );

    const result = await runCliProcess(projectDir, {
      GIT_CONFIG_GLOBAL: gitConfigPath,
    });

    expect(result.code).toBe(0);
    expect(result.output).toContain('Skills install complete');
    await expect(
      readFile(
        join(projectDir, '.agents/skills/github-installed/SKILL.md'),
        'utf-8'
      )
    ).resolves.toBe('# GitHub Skill');
    await expect(
      readFile(
        join(projectDir, '.agents/skills/gitlab-installed/SKILL.md'),
        'utf-8'
      )
    ).resolves.toBe('# GitLab Skill');
  });
});

const createGitRepo = async (
  repoDir: string,
  skillPath: string,
  skillContent: string
): Promise<string> => {
  const skillDir = join(repoDir, skillPath);
  await mkdir(skillDir, { recursive: true });
  await writeFile(join(skillDir, 'SKILL.md'), skillContent);
  await runCommand('git', ['init', '--initial-branch=main'], repoDir);
  await runCommand('git', ['config', 'user.email', 'test@example.com'], repoDir);
  await runCommand('git', ['config', 'user.name', 'Test User'], repoDir);
  await runCommand('git', ['add', '.'], repoDir);
  await runCommand('git', ['commit', '-m', 'add skill'], repoDir);
  const result = await runCommand('git', ['rev-parse', 'HEAD'], repoDir);
  return result.output.trim();
};

const runCliProcess = async (
  cwd: string,
  env: Record<string, string>
): Promise<{ code: number; output: string }> => {
  const currentDir = dirname(fileURLToPath(import.meta.url));
  const cliPath = join(currentDir, '../../index.ts');
  return runCommand('bun', [cliPath, 'install', '--yes'], cwd, env);
};

const runCommand = async (
  command: string,
  args: string[],
  cwd: string,
  env: Record<string, string> = {}
): Promise<{ code: number; output: string }> =>
  new Promise((resolve, reject) => {
    const child = spawn(command, args, {
      cwd,
      env: { ...process.env, ...env },
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    const stdout: string[] = [];
    const stderr: string[] = [];
    child.stdout.setEncoding('utf-8');
    child.stderr.setEncoding('utf-8');
    child.stdout.on('data', (chunk: string) => stdout.push(chunk));
    child.stderr.on('data', (chunk: string) => stderr.push(chunk));
    child.on('error', reject);
    child.on('close', (code) => {
      const output = `${stdout.join('')}${stderr.join('')}`;
      if (code !== 0) {
        reject(new Error(`${command} ${args.join(' ')} failed:\n${output}`));
        return;
      }

      resolve({ code: code ?? 0, output });
    });
  });

const mkdtemp = async () => {
  const { mkdtemp } = await import('node:fs/promises');
  const { tmpdir } = await import('node:os');
  return mkdtemp(join(tmpdir(), 'ai-pkgs-e2e-'));
};

const rmTemp = async (dir: string) => {
  const { rm } = await import('node:fs/promises');
  await rm(dir, { force: true, recursive: true });
};

import { readFile } from 'node:fs/promises';
import { isAbsolute, resolve } from 'node:path';
import * as p from '@clack/prompts';
import pc from 'picocolors';
import { match } from 'ts-pattern';
import { installSkills } from './install';
import { parseAiPackageManifest } from './manifest';
import type { AiPackageManifest, InstallProgress } from './types';

export type InstallCommandOptions = {
  manifest?: string;
  dir?: string;
  yes?: boolean;
};

export type InstallCommandRuntime = {
  cwd: string;
  confirm?: typeof p.confirm;
  install?: typeof installSkills;
  readTextFile?: typeof readFile;
};

/**
 * Run the `install` command action registered by `cac`.
 *
 * @example
 * await runInstallCommand({ yes: true }, { cwd: '/repo' });
 * // Reads /repo/ai-package.json and installs declared skills into
 * // /repo/.agents/skills. It does not mutate the manifest.
 */
export const runInstallCommand = async (
  options: InstallCommandOptions,
  runtime: InstallCommandRuntime
): Promise<number> => {
  p.intro(pc.bold('AI package skills installer'));

  try {
    const projectDir = resolve(runtime.cwd, options.dir ?? '.');
    const manifestPath = resolveManifestPath(
      projectDir,
      options.manifest ?? 'ai-package.json'
    );
    const manifest = await readManifest(manifestPath, runtime);

    if (manifest.skills.length === 0) {
      p.outro(pc.yellow('No skills declared in ai-package.json'));
      return 0;
    }

    p.note(formatSkillSummary(manifest), 'Install plan');

    if (options.yes !== true) {
      const confirmed = await (runtime.confirm ?? p.confirm)({
        message: buildConfirmMessage(manifest.skills.length),
        initialValue: true,
      });

      if (confirmed !== true) {
        p.cancel('Install cancelled');
        return 1;
      }
    }

    const spinner = p.spinner();
    spinner.start('Installing skills');
    const result = await (runtime.install ?? installSkills)({
      manifest,
      projectDir,
      onProgress: (progress) => {
        spinner.message(formatProgress(progress));
      },
    });

    spinner.stop(`Installed ${result.installed.length} skill(s)`);
    for (const skill of result.installed) {
      p.log.success(`${pc.cyan(skill.name)} -> ${pc.dim(skill.targetDir)}`);
    }
    p.outro(pc.green('Skills install complete'));
    return 0;
  } catch (error) {
    p.log.error(error instanceof Error ? error.message : String(error));
    p.outro(pc.red('Skills install failed'));
    return 1;
  }
};

export const resolveManifestPath = (
  projectDir: string,
  manifestPath: string
): string => {
  if (isAbsolute(manifestPath)) {
    return manifestPath;
  }

  return resolve(projectDir, manifestPath);
};

export const formatSkillSummary = (manifest: AiPackageManifest): string =>
  manifest.skills
    .map((skill) => {
      const source = match(skill)
        .with({ provider: 'file' }, (entry) => `file:${entry.packageId}`)
        .otherwise((entry) => `${entry.provider}:${entry.packageId}@${entry.ref}`);
      return `${skill.name}\n  ${source}\n  ${skill.path}`;
    })
    .join('\n\n');

export const buildConfirmMessage = (count: number): string =>
  `Install ${count} skill${count === 1 ? '' : 's'} into .agents/skills?`;

export const formatProgress = (progress: InstallProgress): string =>
  match(progress.status)
    .with('cloning', () => `cloning: ${progress.name}`)
    .with('copying', () => `copying: ${progress.name}`)
    .with('installed', () => `installed: ${progress.name}`)
    .exhaustive();

const readManifest = async (
  manifestPath: string,
  runtime: InstallCommandRuntime
): Promise<AiPackageManifest> => {
  const readTextFile = runtime.readTextFile ?? readFile;
  const raw = await readTextFile(manifestPath, 'utf-8');
  return parseAiPackageManifest(JSON.parse(raw), manifestPath);
};

