import { readFile } from 'node:fs/promises';
import { isAbsolute, resolve } from 'node:path';
import * as p from '@clack/prompts';
import pc from 'picocolors';
import { match } from 'ts-pattern';
import { installSkills } from './install';
import { parseAiPackageManifest } from './manifest';
import type { AiPackageManifest, InstallProgress } from './types';

export type InstallCommandOptions = {
  manifest?: string;
  dir?: string;
  yes?: boolean;
};

export type InstallCommandRuntime = {
  cwd: string;
  confirm: typeof p.confirm;
  install: typeof installSkills;
  readTextFile: typeof readFile;
};

export type InstallCommandRuntimeOverrides = Partial<
  Omit<InstallCommandRuntime, 'cwd'>
>;

export const createInstallCommandRuntime = (
  cwd: string,
  overrides: InstallCommandRuntimeOverrides = {}
): InstallCommandRuntime => ({
  cwd,
  confirm: overrides.confirm ?? p.confirm,
  install: overrides.install ?? installSkills,
  readTextFile: overrides.readTextFile ?? readFile,
});

/**
 * Run the `install` command action registered by `cac`.
 *
 * @example
 * await runInstallCommand({ yes: true }, { cwd: '/repo' });
 * // Reads /repo/ai-package.json and installs declared skills into
 * // /repo/.agents/skills. It does not mutate the manifest.
 */
export const runInstallCommand = async (
  options: InstallCommandOptions,
  runtime: InstallCommandRuntime
): Promise<number> => {
  p.intro(pc.bold('AI package skills installer'));

  try {
    const projectDir = resolve(runtime.cwd, options.dir ?? '.');
    const manifestPath = resolveManifestPath(
      projectDir,
      options.manifest ?? 'ai-package.json'
    );
    const manifest = await readManifest(manifestPath, runtime);

    if (manifest.skills.length === 0) {
      p.outro(pc.yellow('No skills declared in ai-package.json'));
      return 0;
    }

    p.note(formatSkillSummary(manifest), 'Install plan');

    if (options.yes !== true) {
      const confirmed = await runtime.confirm({
        message: buildConfirmMessage(manifest.skills.length),
        initialValue: true,
      });

      if (confirmed !== true) {
        p.cancel('Install cancelled');
        return 1;
      }
    }

    const spinner = p.spinner();
    spinner.start('Installing skills');
    const result = await runtime.install({
      manifest,
      projectDir,
      onProgress: (progress) => {
        spinner.message(formatProgress(progress));
      },
    });

    spinner.stop(`Installed ${result.installed.length} skill(s)`);
    for (const skill of result.installed) {
      p.log.success(`${pc.cyan(skill.name)} -> ${pc.dim(skill.targetDir)}`);
    }
    p.outro(pc.green('Skills install complete'));
    return 0;
  } catch (error) {
    p.log.error(formatInstallError(error));
    p.outro(pc.red('Skills install failed'));
    return 1;
  }
};

export const resolveManifestPath = (
  projectDir: string,
  manifestPath: string
): string => {
  if (isAbsolute(manifestPath)) {
    return manifestPath;
  }

  return resolve(projectDir, manifestPath);
};

export const formatSkillSummary = (manifest: AiPackageManifest): string =>
  manifest.skills
    .map((skill) => {
      const source = match(skill)
        .with({ provider: 'file' }, (entry) => `file:${entry.packageId}`)
        .otherwise((entry) => `${entry.provider}:${entry.packageId}@${entry.ref}`);
      return `${skill.name}\n  ${source}\n  ${skill.path}`;
    })
    .join('\n\n');

export const buildConfirmMessage = (count: number): string =>
  `Install ${count} skill${count === 1 ? '' : 's'} into .agents/skills?`;

export const formatProgress = (progress: InstallProgress): string =>
  match(progress.status)
    .with('cloning', () => `cloning: ${progress.name}`)
    .with('copying', () => `copying: ${progress.name}`)
    .with('installed', () => `installed: ${progress.name}`)
    .exhaustive();

export const formatInstallError = (error: unknown): string => {
  if (error instanceof Error) {
    return error.message;
  }

  return String(error);
};

const readManifest = async (
  manifestPath: string,
  runtime: InstallCommandRuntime
): Promise<AiPackageManifest> => {
  const raw = await runtime.readTextFile(manifestPath, 'utf-8');
  return parseAiPackageManifest(JSON.parse(raw), manifestPath);
};

import { updateSettings } from '@clack/core';
import cac, { type CAC } from 'cac';
import {
  createInstallCommandRuntime,
  runInstallCommand,
  type InstallCommandRuntimeOverrides,
} from './install-command';

export const runCli = async (
  argv = process.argv,
  cwd = process.cwd(),
  runtime: InstallCommandRuntimeOverrides = {}
): Promise<number> => {
  updateSettings({
    messages: {
      cancel: 'Install cancelled',
      error: 'Install failed',
    },
  });

  try {
    const cli = buildCli(createInstallCommandRuntime(cwd, runtime));
    cli.parse(argv, { run: false });
    return await resolveCliResult(cli.runMatchedCommand());
  } catch (error) {
    process.stderr.write(`${formatCliError(error)}\n`);
    process.stderr.write('Run ai-pkgs --help for usage.\n');
    return 1;
  }
};

/**
 * Build the command parser. The default command intentionally installs from
 * `ai-package.json`, matching package managers where no subcommand means
 * "restore this project".
 */
export const buildCli = (runtime: InstallCommandRuntime): CAC => {
  const cli = cac('ai-pkgs');
  const action = (options: InstallCommandOptions) =>
    runInstallCommand(options, runtime);

  cli.usage('[install] [options]');
  cli.help();

  cli
    .command('', 'Install skills from ai-package.json')
    .option('-m, --manifest <path>', 'Path to ai-package.json')
    .option('-C, --dir <path>', 'Project directory to install into')
    .option('-y, --yes', 'Skip confirmation prompts')
    .action(action);

  cli
    .command('install', 'Install skills from ai-package.json')
    .option('-m, --manifest <path>', 'Path to ai-package.json')
    .option('-C, --dir <path>', 'Project directory to install into')
    .option('-y, --yes', 'Skip confirmation prompts')
    .example('ai-pkgs install --yes')
    .example('ai-pkgs install --manifest config/ai-package.json --dir .')
    .action(action);

  return cli;
};

type InstallCommandOptions = {
  manifest?: string;
  dir?: string;
  yes?: boolean;
};

export const resolveCliResult = async (result: unknown): Promise<number> => {
  if (isPromiseLike(result)) {
    return (await result) as number;
  }

  if (typeof result === 'number') {
    return result;
  }

  return 0;
};

export const formatCliError = (error: unknown): string => {
  if (error instanceof Error) {
    return error.message;
  }

  return String(error);
};

const isPromiseLike = (value: unknown): value is Promise<unknown> =>
  typeof value === 'object' &&
  value !== null &&
  'then' in value &&
  typeof value.then === 'function';

import { dirname, isAbsolute, resolve } from 'node:path';
import { P, match } from 'ts-pattern';
import type {
  AiPackageManifest,
  FileSkillEntry,
  RemoteProvider,
  RemoteSkillEntry,
  SkillEntry,
} from './types';

type RawManifest = {
  skills?: unknown;
  skill?: unknown;
};

type RawSkillEntry = {
  source?: unknown;
  version?: unknown;
  path?: unknown;
};

const REMOTE_PROVIDERS = new Set<RemoteProvider>(['github', 'gitlab']);
const COMMIT_SHA_RE = /^[0-9a-f]{7,40}$/i;

export const parseAiPackageManifest = (
  raw: unknown,
  manifestPath: string
): AiPackageManifest => {
  if (!isRecord(raw)) {
    throw new Error(`${manifestPath} must be a JSON object`);
  }

  const manifest = raw as RawManifest;
  if (manifest.skills === undefined) {
    if (manifest.skill !== undefined) {
      throw new Error(
        `${manifestPath} must use the top-level "skills" object, not "skill"`
      );
    }
    throw new Error(`${manifestPath} must contain a top-level "skills" object`);
  }

  if (!isRecord(manifest.skills)) {
    throw new Error(`${manifestPath} top-level "skills" must be an object`);
  }

  const manifestDir = dirname(resolve(manifestPath));
  const skills: SkillEntry[] = [];
  for (const [name, value] of Object.entries(manifest.skills)) {
    skills.push(parseSkillEntry(name, value, manifestDir));
  }

  return { skills };
};

const parseSkillEntry = (
  name: string,
  raw: unknown,
  manifestDir: string
): SkillEntry => {
  validateSkillName(name);

  if (!isRecord(raw)) {
    throw new Error(`Skill "${name}" must be an object`);
  }

  const entry = raw as RawSkillEntry;
  if (typeof entry.source !== 'string' || entry.source.trim().length === 0) {
    throw new Error(`Skill "${name}" source is required`);
  }

  if (typeof entry.path !== 'string' || entry.path.trim().length === 0) {
    throw new Error(`Skill "${name}" path is required`);
  }

  const path = sanitizeManifestPath(entry.path, `Skill "${name}" path`);
  const source = parseSource(entry.source, name);

  if (source.provider === 'file') {
    return {
      name,
      provider: 'file',
      packageId: source.packageId,
      sourceRoot: resolveFileSource(manifestDir, source.packageId),
      path,
    } satisfies FileSkillEntry;
  }

  if (source.provider === 'marketplace') {
    throw new Error('marketplace sources are not supported by this installer yet');
  }

  const version = parseRemoteVersion(entry.version, name);
  return {
    name,
    provider: source.provider,
    packageId: source.packageId,
    cloneUrl: buildCloneUrl(source.provider, source.packageId),
    ref: version.ref,
    commitSha: version.commitSha,
    path,
  } satisfies RemoteSkillEntry;
};

const parseSource = (
  source: string,
  skillName: string
):
  | { provider: RemoteProvider; packageId: string }
  | { provider: 'file'; packageId: string }
  | { provider: 'marketplace'; packageId: string } => {
  const separator = source.indexOf(':');
  if (separator <= 0) {
    throw new Error(
      `Skill "${skillName}" source must use <provider>:<package-id>`
    );
  }

  const provider = source.slice(0, separator);
  const packageId = source.slice(separator + 1).replace(/^\/+|\/+$/g, '');
  if (packageId.length === 0) {
    throw new Error(`Skill "${skillName}" source package id is required`);
  }

  return match(provider)
    .with(P.when((value) => REMOTE_PROVIDERS.has(value as RemoteProvider)), () => {
      const remoteProvider = provider as RemoteProvider;
      validateRemotePackageId(remoteProvider, packageId, skillName);
      return { provider: remoteProvider, packageId };
    })
    .with('file', () => ({ provider, packageId: source.slice(separator + 1) }))
    .with('marketplace', () => ({ provider, packageId }))
    .otherwise(() => {
      throw new Error(`Unsupported source provider "${provider}"`);
    });
};

const parseRemoteVersion = (
  version: unknown,
  skillName: string
): { ref: string; commitSha: string } => {
  if (typeof version !== 'string' || version.trim().length === 0) {
    throw new Error(`Skill "${skillName}" version is required for remote sources`);
  }

  const separator = version.lastIndexOf('@');
  if (separator <= 0 || separator === version.length - 1) {
    throw new Error(
      `Skill "${skillName}" version must use <ref>@<commitSha>`
    );
  }

  const ref = version.slice(0, separator);
  const commitSha = version.slice(separator + 1);
  if (!COMMIT_SHA_RE.test(commitSha)) {
    throw new Error(
      `Skill "${skillName}" version must use <ref>@<commitSha>`
    );
  }

  return { ref, commitSha };
};

export const sanitizeManifestPath = (path: string, label = 'path'): string => {
  const normalized = path.trim().replace(/\\/g, '/').replace(/^\.\/+/, '');
  if (normalized.length === 0) {
    throw new Error(`${label} is required`);
  }

  if (isAbsolute(normalized)) {
    throw new Error(`${label} must stay inside the source`);
  }

  const segments = normalized.split('/');
  if (segments.some((segment) => segment === '..')) {
    throw new Error(`${label} must stay inside the source`);
  }

  return normalized;
};

const validateSkillName = (name: string) => {
  if (
    name.trim().length === 0 ||
    name === '.' ||
    name === '..' ||
    name.includes('/') ||
    name.includes('\\')
  ) {
    throw new Error(`Invalid skill name "${name}"`);
  }
};

const validateRemotePackageId = (
  provider: RemoteProvider,
  packageId: string,
  skillName: string
) => {
  const segments = packageId.split('/').filter(Boolean);
  if (provider === 'github' && segments.length !== 2) {
    throw new Error(
      `Skill "${skillName}" github source must use github:owner/repo`
    );
  }

  if (provider === 'gitlab' && segments.length < 2) {
    throw new Error(
      `Skill "${skillName}" gitlab source must use gitlab:group/repo`
    );
  }
};

const buildCloneUrl = (provider: RemoteProvider, packageId: string): string => {
  if (provider === 'github') {
    return `https://github.com/${packageId}.git`;
  }

  return `https://gitlab.com/${packageId}.git`;
};

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    coverage: {
      all: true,
      exclude: ['src/tests/**', 'src/types.ts'],
      include: ['src/**/*.ts'],
      provider: 'v8',
      reporter: ['text', 'json-summary'],
      thresholds: {
        branches: 95,
        functions: 95,
        lines: 95,
        perFile: true,
        statements: 95,
      },
    },
  },
});

